# useEffect 实战代码示例集

## 常见问题及解决方案

### 问题 1：无限重渲染案例分析

#### 🔴 错误示例：对象依赖导致无限循环

```javascript
function UserDashboard() {
  const [user, setUser] = useState(null);

  // ❌ 错误：每次渲染都会创建新的对象
  const config = {
    theme: 'dark',
    showNotifications: true
  };

  useEffect(() => {
    fetchUserWithConfig(config).then(setUser);
  }, [config]); // config 每次都是新对象，导致无限循环

  return <div>{user?.name}</div>;
}
```

#### 🟢 正确解决方案：

```javascript
function UserDashboard() {
  const [user, setUser] = useState(null);

  // 方案1：将配置移到 effect 内部
  useEffect(() => {
    const config = {
      theme: 'dark',
      showNotifications: true
    };
    fetchUserWithConfig(config).then(setUser);
  }, []); // 无外部依赖

  // 方案2：使用 useMemo 缓存配置对象
  const config = useMemo(() => ({
    theme: 'dark',
    showNotifications: true
  }), []);

  useEffect(() => {
    fetchUserWithConfig(config).then(setUser);
  }, [config]);

  return <div>{user?.name}</div>;
}
```

### 问题 2：函数依赖的正确处理

#### 🔴 错误示例：函数引用不稳定

```javascript
function SearchComponent({ searchTerm }) {
  const [results, setResults] = useState([]);

  // ❌ 每次渲染都会创建新函数
  const performSearch = (term) => {
    return fetch(`/api/search?q=${term}`).then(res => res.json());
  };

  useEffect(() => {
    performSearch(searchTerm).then(setResults);
  }, [searchTerm, performSearch]); // performSearch 每次都变，导致不必要的请求

  return <div>{/* 渲染结果 */}</div>;
}
```

#### 🟢 正确解决方案：

```javascript
function SearchComponent({ searchTerm }) {
  const [results, setResults] = useState([]);

  // 方案1：使用 useCallback 稳定函数引用
  const performSearch = useCallback((term) => {
    return fetch(`/api/search?q=${term}`).then(res => res.json());
  }, []);

  useEffect(() => {
    performSearch(searchTerm).then(setResults);
  }, [searchTerm, performSearch]);

  // 方案2：直接在 effect 内定义函数
  useEffect(() => {
    const performSearch = (term) => {
      return fetch(`/api/search?q=${term}`).then(res => res.json());
    };

    performSearch(searchTerm).then(setResults);
  }, [searchTerm]);

  return <div>{/* 渲染结果 */}</div>;
}
```

### 问题 3：竞态条件处理

#### 🔴 问题场景：快速切换导致数据错乱

```javascript
function UserProfile({ userId }) {
  const [user, setUser] = useState(null);
  const [loading, setLoading] = useState(false);

  // ❌ 可能的竞态条件
  useEffect(() => {
    setLoading(true);
    fetchUser(userId)
      .then(userData => {
        setUser(userData);
        setLoading(false);
      });
  }, [userId]);

  return loading ? <Spinner /> : <div>{user?.name}</div>;
}
```

#### 🟢 完整的竞态条件解决方案：

```javascript
function UserProfile({ userId }) {
  const [user, setUser] = useState(null);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState(null);

  useEffect(() => {
    // 使用 AbortController 取消请求
    const controller = new AbortController();
    let isCancelled = false;

    const loadUser = async () => {
      if (!userId) return;

      setLoading(true);
      setError(null);

      try {
        const userData = await fetchUser(userId, {
          signal: controller.signal
        });

        // 检查组件是否已卸载或依赖已变化
        if (!isCancelled) {
          setUser(userData);
          setLoading(false);
        }
      } catch (err) {
        if (!isCancelled && err.name !== 'AbortError') {
          setError(err);
          setLoading(false);
        }
      }
    };

    loadUser();

    // 清理函数
    return () => {
      isCancelled = true;
      controller.abort();
    };
  }, [userId]);

  if (loading) return <Spinner />;
  if (error) return <ErrorMessage error={error} />;
  return <div>{user?.name}</div>;
}
```

## 企业级自定义 Hook 模式

### 1. 通用数据获取 Hook

```javascript
function useAsyncData(asyncFunction, dependencies = [], options = {}) {
  const [data, setData] = useState(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);

  const {
    immediate = true,
    onSuccess,
    onError,
    resetOnDepsChange = true
  } = options;

  const execute = useCallback(async (...args) => {
    const controller = new AbortController();

    try {
      setLoading(true);
      setError(null);

      if (resetOnDepsChange) {
        setData(null);
      }

      const result = await asyncFunction(...args, {
        signal: controller.signal
      });

      setData(result);
      onSuccess?.(result);
    } catch (err) {
      if (err.name !== 'AbortError') {
        setError(err);
        onError?.(err);
      }
    } finally {
      setLoading(false);
    }

    return controller;
  }, [asyncFunction, onSuccess, onError, resetOnDepsChange]);

  useEffect(() => {
    if (!immediate) return;

    const controller = execute();
    return () => controller?.abort();
  }, dependencies);

  return {
    data,
    loading,
    error,
    execute: () => execute(),
    reset: () => {
      setData(null);
      setError(null);
      setLoading(false);
    }
  };
}

// 使用示例
function UserList() {
  const {
    data: users,
    loading,
    error,
    execute: refetchUsers
  } = useAsyncData(
    fetchUsers,
    [],
    {
      onSuccess: (users) => console.log(`Loaded ${users.length} users`),
      onError: (err) => toast.error('Failed to load users')
    }
  );

  return (
    <div>
      {loading && <Spinner />}
      {error && <ErrorMessage error={error} retry={refetchUsers} />}
      {users?.map(user => <UserCard key={user.id} user={user} />)}
    </div>
  );
}
```

### 2. 防抖和节流 Hook

```javascript
function useDebounce(value, delay) {
  const [debouncedValue, setDebouncedValue] = useState(value);

  useEffect(() => {
    const timer = setTimeout(() => {
      setDebouncedValue(value);
    }, delay);

    return () => clearTimeout(timer);
  }, [value, delay]);

  return debouncedValue;
}

function useThrottle(value, delay) {
  const [throttledValue, setThrottledValue] = useState(value);
  const lastExecuted = useRef(Date.now());

  useEffect(() => {
    if (Date.now() >= lastExecuted.current + delay) {
      lastExecuted.current = Date.now();
      setThrottledValue(value);
    } else {
      const timer = setTimeout(() => {
        lastExecuted.current = Date.now();
        setThrottledValue(value);
      }, delay);

      return () => clearTimeout(timer);
    }
  }, [value, delay]);

  return throttledValue;
}

// 使用示例：搜索功能
function SearchInput() {
  const [searchTerm, setSearchTerm] = useState('');
  const [results, setResults] = useState([]);
  const debouncedSearchTerm = useDebounce(searchTerm, 300);

  useEffect(() => {
    if (debouncedSearchTerm) {
      searchAPI(debouncedSearchTerm).then(setResults);
    } else {
      setResults([]);
    }
  }, [debouncedSearchTerm]);

  return (
    <div>
      <input
        value={searchTerm}
        onChange={(e) => setSearchTerm(e.target.value)}
        placeholder="搜索..."
      />
      <SearchResults results={results} />
    </div>
  );
}
```

### 3. 本地存储同步 Hook

```javascript
function useLocalStorage(key, initialValue) {
  const [storedValue, setStoredValue] = useState(() => {
    try {
      const item = window.localStorage.getItem(key);
      return item ? JSON.parse(item) : initialValue;
    } catch (error) {
      console.error(`Error reading localStorage key "${key}":`, error);
      return initialValue;
    }
  });

  const setValue = useCallback((value) => {
    try {
      const valueToStore = value instanceof Function ? value(storedValue) : value;
      setStoredValue(valueToStore);
      window.localStorage.setItem(key, JSON.stringify(valueToStore));
    } catch (error) {
      console.error(`Error setting localStorage key "${key}":`, error);
    }
  }, [key, storedValue]);

  // 监听其他标签页的存储变化
  useEffect(() => {
    const handleStorageChange = (e) => {
      if (e.key === key && e.newValue !== null) {
        try {
          setStoredValue(JSON.parse(e.newValue));
        } catch (error) {
          console.error(`Error parsing localStorage key "${key}":`, error);
        }
      }
    };

    window.addEventListener('storage', handleStorageChange);
    return () => window.removeEventListener('storage', handleStorageChange);
  }, [key]);

  return [storedValue, setValue];
}

// 使用示例
function UserPreferences() {
  const [theme, setTheme] = useLocalStorage('theme', 'light');
  const [language, setLanguage] = useLocalStorage('language', 'zh');

  return (
    <div>
      <ThemeSelector theme={theme} onChange={setTheme} />
      <LanguageSelector language={language} onChange={setLanguage} />
    </div>
  );
}
```

## 性能优化最佳实践

### 1. 条件执行优化

```javascript
function OptimizedComponent({ userId, isVisible }) {
  const [userData, setUserData] = useState(null);

  // ✅ 条件执行，避免不必要的 API 调用
  useEffect(() => {
    if (!isVisible || !userId) return;

    let cancelled = false;

    fetchUserData(userId)
      .then(data => {
        if (!cancelled) {
          setUserData(data);
        }
      });

    return () => {
      cancelled = true;
    };
  }, [userId, isVisible]);

  // ✅ 基于可见性的动态清理
  useEffect(() => {
    if (!isVisible) {
      setUserData(null); // 组件不可见时清理数据
    }
  }, [isVisible]);

  return isVisible ? <UserDisplay data={userData} /> : null;
}
```

### 2. 批量更新优化

```javascript
function BatchUpdateComponent() {
  const [count, setCount] = useState(0);
  const [status, setStatus] = useState('idle');

  // ✅ 使用 unstable_batchedUpdates 批量更新
  useEffect(() => {
    const timer = setInterval(() => {
      // React 18+ 自动批处理，无需手动批处理
      setCount(c => c + 1);
      setStatus('updating');
    }, 1000);

    return () => clearInterval(timer);
  }, []);

  return <div>Count: {count}, Status: {status}</div>;
}
```

## 调试工具和技巧

### 1. Effect 执行追踪

```javascript
function useEffectDebugger(effectHook, dependencies, dependencyNames = []) {
  const previousDeps = usePrevious(dependencies);
  const changedDeps = previousDeps
    ? dependencies.reduce((accum, dependency, index) => {
        if (dependency !== previousDeps[index]) {
          const keyName = dependencyNames[index] || index;
          return {
            ...accum,
            [keyName]: {
              before: previousDeps[index],
              after: dependency
            }
          };
        }
        return accum;
      }, {})
    : {};

  if (Object.keys(changedDeps).length) {
    console.log('[useEffect] Dependencies changed:', changedDeps);
  }

  return effectHook();
}

// 使用示例
function DebuggableComponent({ userId, filter }) {
  useEffectDebugger(
    () => {
      console.log('Effect executed');
      fetchData(userId, filter);
    },
    [userId, filter],
    ['userId', 'filter']
  );
}

function usePrevious(value) {
  const ref = useRef();
  useEffect(() => {
    ref.current = value;
  });
  return ref.current;
}
```

### 2. 性能监控

```javascript
function useEffectPerformance(name, effect, deps) {
  useEffect(() => {
    const start = performance.now();
    console.group(`🚀 Effect "${name}" started`);

    const cleanup = effect();

    const duration = performance.now() - start;
    console.log(`⏱️ Effect "${name}" took ${duration.toFixed(2)}ms`);
    console.groupEnd();

    return cleanup;
  }, deps);
}

// 使用示例
function PerformanceTrackedComponent() {
  useEffectPerformance(
    'Data Loading',
    () => {
      return loadHeavyData().then(setData);
    },
    []
  );
}
